Implementation file: src/game-of-life.ts
Passing tests: 4
Recent changes: Implemented neighbor-counting logic using a Set for alive cells. Live cells with 2-3 neighbors survive (filter). Uses `${x},${y}` string keys in a Set for O(1) lookups. Nested loops iterate over 8 neighbors.

Current implementation:
```typescript
export const nextGeneration = (liveCells: number[][]): number[][] => {
  const alive = new Set(liveCells.map(([x, y]) => `${x},${y}`));

  return liveCells.filter(([x, y]) => {
    let count = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (alive.has(`${x + dx},${y + dy}`)) count++;
      }
    }
    return count >= 2 && count <= 3;
  });
};
```

